log() {
  local level=$1; shift
  echo "[$(date '+%Y-%m-%d %H:%M:%S')] [$level] $*"
}
log INFO 'Deploy started'

get_version() {
  local version
  version=$(cat VERSION)
  echo "$version"
}
VERSION=$(get_version)

case "$1" in
  start)   start_service ;;
  stop)    stop_service ;;
  restart) stop_service; start_service ;;
  *)       echo "Usage: $0 {start|stop|restart}"; exit 1 ;;
esac

case "$(uname -s)" in
  Linux*)  OS=linux ;;
  Darwin*) OS=macos ;;
  *)       OS=unknown ;;
esac

usage() { echo "Usage: $0 [-e env] [-v]"; exit 1; }

VERBOSE=false
ENV='dev'

while getopts 'e:v' opt; do
  case $opt in
    e) ENV=$OPTARG ;;
    v) VERBOSE=true ;;
    *) usage ;;
  esac
done
shift $((OPTIND - 1))
